import { createFileRoute } from "@tanstack/react-router";

interface ContactPayload {
  name?: string;
  email?: string;
  company?: string;
  message?: string;
}

// Logo is injected at build time by scripts/inject-logo.ts
// data:image/png;base64, is replaced with the real base64 data URI
const LOGO_DATA_URI = "data:image/png;base64,";

function escape(s: string) {
  return s
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/\n/g, "<br>");
}

function buildHtml(
  name: string,
  email: string,
  company: string,
  message: string,
): string {
  const companyRow = company
    ? `<tr>
        <td style="padding-bottom:16px;">
          <table width="100%" cellpadding="0" cellspacing="0" style="background:#f8fafc;border-radius:8px;border-left:4px solid #1a5276;overflow:hidden;">
            <tr>
              <td style="padding:14px 18px;">
                <div style="font-size:11px;font-weight:700;letter-spacing:1px;text-transform:uppercase;color:#6b7280;margin-bottom:4px;">Company</div>
                <div style="font-size:15px;color:#111827;font-weight:600;">${escape(company)}</div>
              </td>
            </tr>
          </table>
        </td>
      </tr>`
    : "";

  return `<!DOCTYPE html>
<html lang="en">
<head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"></head>
<body style="margin:0;padding:0;background:#f1f5f9;font-family:'Segoe UI',Arial,sans-serif;">
  <table width="100%" cellpadding="0" cellspacing="0" style="background:#f1f5f9;padding:40px 16px;">
    <tr><td align="center">
      <table width="600" cellpadding="0" cellspacing="0" style="max-width:600px;width:100%;border-radius:12px;overflow:hidden;box-shadow:0 4px 24px rgba(0,0,0,0.10);">

        <!-- Header -->
        <tr>
          <td style="background:linear-gradient(135deg,#0f3460 0%,#1a5276 60%,#1f618d 100%);padding:36px 40px;text-align:center;">
            <div style="color:#ffffff;font-size:20px;font-weight:700;letter-spacing:0.5px;">VTS Universe Sdn Bhd</div>
            <div style="color:#93c5fd;font-size:13px;margin-top:4px;letter-spacing:1px;text-transform:uppercase;">New Enquirey</div>
          </td>
        </tr>

        <!-- Body -->
        <tr>
          <td style="background:#ffffff;padding:40px;">
            <p style="margin:0 0 28px;font-size:15px;color:#374151;line-height:1.6;">
              A new enquiry has been submitted via the VTS Universe website. Details are below.
            </p>

            <table width="100%" cellpadding="0" cellspacing="0">
              <tr>
                <td style="padding-bottom:16px;">
                  <table width="100%" cellpadding="0" cellspacing="0" style="background:#f8fafc;border-radius:8px;border-left:4px solid #1a5276;overflow:hidden;">
                    <tr>
                      <td style="padding:14px 18px;">
                        <div style="font-size:11px;font-weight:700;letter-spacing:1px;text-transform:uppercase;color:#6b7280;margin-bottom:4px;">Name</div>
                        <div style="font-size:15px;color:#111827;font-weight:600;">${escape(name)}</div>
                      </td>
                    </tr>
                  </table>
                </td>
              </tr>
              <tr>
                <td style="padding-bottom:16px;">
                  <table width="100%" cellpadding="0" cellspacing="0" style="background:#f8fafc;border-radius:8px;border-left:4px solid #1a5276;overflow:hidden;">
                    <tr>
                      <td style="padding:14px 18px;">
                        <div style="font-size:11px;font-weight:700;letter-spacing:1px;text-transform:uppercase;color:#6b7280;margin-bottom:4px;">Email</div>
                        <div style="font-size:15px;color:#1a5276;font-weight:600;">
                          <a href="mailto:${escape(email)}" style="color:#1a5276;text-decoration:none;">${escape(email)}</a>
                        </div>
                      </td>
                    </tr>
                  </table>
                </td>
              </tr>
              ${companyRow}
              <tr>
                <td>
                  <table width="100%" cellpadding="0" cellspacing="0" style="background:#f8fafc;border-radius:8px;border-left:4px solid #1a5276;overflow:hidden;">
                    <tr>
                      <td style="padding:14px 18px;">
                        <div style="font-size:11px;font-weight:700;letter-spacing:1px;text-transform:uppercase;color:#6b7280;margin-bottom:8px;">Inquiries</div>
                        <div style="font-size:15px;color:#111827;line-height:1.7;">${escape(message)}</div>
                      </td>
                    </tr>
                  </table>
                </td>
              </tr>
            </table>

            <table width="100%" cellpadding="0" cellspacing="0" style="margin-top:32px;">
              <tr>
                <td align="center">
                  <a href="mailto:${escape(email)}" style="display:inline-block;background:linear-gradient(135deg,#0f3460,#1f618d);color:#ffffff;font-size:14px;font-weight:600;padding:12px 32px;border-radius:8px;text-decoration:none;letter-spacing:0.3px;">
                    Reply to ${escape(name)}
                  </a>
                </td>
              </tr>
            </table>
          </td>
        </tr>

        <!-- Footer -->
        <tr>
          <td style="background:#f8fafc;border-top:1px solid #e5e7eb;padding:24px 40px;text-align:center;">
            <div style="font-size:12px;color:#9ca3af;line-height:1.6;">
              This email was sent automatically from the VTS Universe website contact form.<br>
              <strong style="color:#6b7280;">VTS Universe Sdn Bhd</strong> &middot; 106-2 Jalan LP 7/4, Taman Lestari Perdana, 43300 Seri Kembangan, Selangor, Malaysia
            </div>
          </td>
        </tr>

      </table>
    </td></tr>
  </table>
</body>
</html>`;
}

export const Route = createFileRoute("/api/contact")({
  server: {
    handlers: {
      POST: async ({ request }) => {
        const apiKey = process.env.RESEND_API_KEY;
        if (!apiKey) {
          return Response.json(
            { ok: false, error: "Email service not configured." },
            { status: 500 },
          );
        }

        let body: ContactPayload;
        try {
          body = (await request.json()) as ContactPayload;
        } catch {
          return Response.json(
            { ok: false, error: "Invalid request body." },
            { status: 400 },
          );
        }

        const name = (body.name ?? "").trim();
        const email = (body.email ?? "").trim();
        const company = (body.company ?? "").trim();
        const message = (body.message ?? "").trim();

        if (!name || !email || !message) {
          return Response.json(
            { ok: false, error: "Missing required fields." },
            { status: 400 },
          );
        }
        if (
          name.length > 200 ||
          email.length > 200 ||
          company.length > 200 ||
          message.length > 5000
        ) {
          return Response.json(
            { ok: false, error: "Input too long." },
            { status: 400 },
          );
        }

        const subject = `New enquiry from ${name}${company ? ` — ${company}` : ""}`;
        const html = buildHtml(name, email, company, message);

        const text = [
          `New enquiry from the VTS Universe website`,
          ``,
          `Name: ${name}`,
          `Email: ${email}`,
          company ? `Company: ${company}` : null,
          ``,
          `Inquiries:`,
          message,
        ]
          .filter((l) => l !== null)
          .join("\n");

        const resendRes = await fetch("https://api.resend.com/emails", {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
            Authorization: `Bearer ${apiKey}`,
          },
          body: JSON.stringify({
            from: "VTS Universe Website <onboarding@resend.dev>",
            to: ["firasfaiqshajoeril@gmail.com"],
            reply_to: email,
            subject,
            html,
            text,
          }),
        });

        if (!resendRes.ok) {
          const errText = await resendRes.text();
          console.error("Resend send failed", resendRes.status, errText);
          return Response.json(
            {
              ok: false,
              error: "Failed to send message. Please email us directly.",
            },
            { status: 502 },
          );
        }

        return Response.json({ ok: true });
      },
    },
  },
});
